import React, { useState, useMemo } from "react";
import "./BatchDashboard.css";

function BatchDashboard({ dashboardData }) {
  const [currentPage, setCurrentPage] = useState(1);
  const [itemsPerPage, setItemsPerPage] = useState(50);
  const [searchTerm, setSearchTerm] = useState("");
  const [activeTab, setActiveTab] = useState("overview");

  if (!dashboardData || !dashboardData.batchResult) {
    return (
      <div className="batch-dashboard">
        <div className="no-data-message">
          <h3>No Batch Analysis Results Available</h3>
          <p>Please run a batch analysis first from the Batch Processing section.</p>
        </div>
      </div>
    );
  }

  const { batchResult } = dashboardData;
  const { dataset_info, risk_analysis, customer_segmentation, feature_analysis, all_predictions, data_source } = batchResult;

  // Calculate percentages for risk distribution
  const totalCustomers = dataset_info.total_customers;
  const riskDistribution = risk_analysis.risk_distribution || {};

  // Calculate risk counts from distribution
  const lowRiskCount = riskDistribution['P3: Low Risk (<=30%)'] || 0;
  const mediumRiskCount = riskDistribution['P2: Moderate Risk (31-70%)'] || 0;
  const highRiskCount = riskDistribution['P1: High Risk (>70%)'] || 0;

  // Filter and paginate ALL predictions
  const filteredPredictions = useMemo(() => {
    if (!all_predictions) return [];
    
    return all_predictions.filter(customer => {
      if (!searchTerm) return true;
      
      const searchLower = searchTerm.toLowerCase();
      return (
        (customer.Customer_ID && customer.Customer_ID.toString().toLowerCase().includes(searchLower)) ||
        (customer.Risk_Level && customer.Risk_Level.toLowerCase().includes(searchLower)) ||
        (customer.Predicted_Churn && customer.Predicted_Churn.toString().toLowerCase().includes(searchLower))
      );
    });
  }, [all_predictions, searchTerm]);

  // Pagination calculations
  const totalPages = Math.ceil(filteredPredictions.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = startIndex + itemsPerPage;
  const currentPredictions = filteredPredictions.slice(startIndex, endIndex);

  // Business Analytics Data Preparation
  const businessAnalyticsData = useMemo(() => {
    if (!all_predictions || all_predictions.length === 0) return null;

    // Payment Method Analysis
    const paymentMethods = {};
    const paymentRisk = {};

    // Tenure Analysis
    const tenureBrackets = {
      '0-3 months': { count: 0, revenue: 0, risk: { high: 0, medium: 0, low: 0 } },
      '3-6 months': { count: 0, revenue: 0, risk: { high: 0, medium: 0, low: 0 } },
      '6-9 months': { count: 0, revenue: 0, risk: { high: 0, medium: 0, low: 0 } },
      '9-12 months': { count: 0, revenue: 0, risk: { high: 0, medium: 0, low: 0 } },
      '12+ months': { count: 0, revenue: 0, risk: { high: 0, medium: 0, low: 0 } }
    };

    // City Tier Analysis
    const cityTiers = { 'Tier 1': 0, 'Tier 2': 0, 'Tier 3': 0 };
    const cityTierRevenue = { 'Tier 1': 0, 'Tier 2': 0, 'Tier 3': 0 };

    // Marital Status Analysis
    const maritalStatus = { 'Single': 0, 'Married': 0, 'Divorced': 0, 'Other': 0 };
    const maritalRisk = {
      'Single': { high: 0, medium: 0, low: 0 },
      'Married': { high: 0, medium: 0, low: 0 },
      'Divorced': { high: 0, medium: 0, low: 0 },
      'Other': { high: 0, medium: 0, low: 0 }
    };

    // Gender Analysis
    const genderData = { 'Male': 0, 'Female': 0, 'Other': 0 };

    // Revenue Analysis
    let totalRevenueAtRisk = 0;
    let highRiskRevenue = 0;
    let mediumRiskRevenue = 0;
    let lowRiskRevenue = 0;

    all_predictions.forEach(customer => {
      const prob = customer.Churn_Probability || 0;
      const tenure = customer.Tenure || 0;
      const orderCount = customer.OrderCount || 0;
      const cashback = customer.CashbackAmount || 0;
      const cityTier = customer.CityTier || customer.city_tier || 2;
      const paymentMethod = customer.PreferredPaymentMode || customer.preferred_payment_mode || 'Unknown';
      const maritalStatusVal = customer.MaritalStatus || customer.marital_status || 'Unknown';
      const gender = customer.Gender || customer.gender || 'Unknown';
      
      // Calculate customer value
      const customerValue = (orderCount * 850) + cashback;
      const revenueAtRisk = customerValue * prob;
      totalRevenueAtRisk += revenueAtRisk;

      // Risk-based revenue
      const riskLevel = prob > 0.7 ? 'high' : prob > 0.3 ? 'medium' : 'low';
      if (riskLevel === 'high') highRiskRevenue += revenueAtRisk;
      else if (riskLevel === 'medium') mediumRiskRevenue += revenueAtRisk;
      else lowRiskRevenue += revenueAtRisk;

      // Payment Method Analysis
      if (!paymentMethods[paymentMethod]) {
        paymentMethods[paymentMethod] = 0;
        paymentRisk[paymentMethod] = { high: 0, medium: 0, low: 0 };
      }
      paymentMethods[paymentMethod]++;
      paymentRisk[paymentMethod][riskLevel]++;

      // Tenure Analysis
      let tenureKey = '12+ months';
      if (tenure <= 3) tenureKey = '0-3 months';
      else if (tenure <= 6) tenureKey = '3-6 months';
      else if (tenure <= 9) tenureKey = '6-9 months';
      else if (tenure <= 12) tenureKey = '9-12 months';
      
      tenureBrackets[tenureKey].count++;
      tenureBrackets[tenureKey].revenue += customerValue;
      tenureBrackets[tenureKey].risk[riskLevel]++;

      // City Tier Analysis
      const tierKey = cityTier === 1 || cityTier === '1' ? 'Tier 1' : 
                     cityTier === 2 || cityTier === '2' ? 'Tier 2' : 'Tier 3';
      cityTiers[tierKey]++;
      cityTierRevenue[tierKey] += customerValue;

      // Marital Status Analysis
      let statusKey = 'Other';
      if (maritalStatusVal.toLowerCase().includes('single')) statusKey = 'Single';
      else if (maritalStatusVal.toLowerCase().includes('married')) statusKey = 'Married';
      else if (maritalStatusVal.toLowerCase().includes('divorced')) statusKey = 'Divorced';
      
      maritalStatus[statusKey]++;
      maritalRisk[statusKey][riskLevel]++;

      // Gender Analysis
      let genderKey = 'Other';
      if (gender.toLowerCase().includes('male')) genderKey = 'Male';
      else if (gender.toLowerCase().includes('female')) genderKey = 'Female';
      
      genderData[genderKey]++;
    });

    return {
      revenue: {
        totalAtRisk: totalRevenueAtRisk,
        highRisk: highRiskRevenue,
        mediumRisk: mediumRiskRevenue,
        lowRisk: lowRiskRevenue
      },
      payments: {
        methods: paymentMethods,
        risk: paymentRisk
      },
      tenure: tenureBrackets,
      geography: {
        cityTiers,
        revenue: cityTierRevenue
      },
      marital: {
        status: maritalStatus,
        risk: maritalRisk
      },
      gender: genderData,
      overall: {
        totalCustomers,
        highRiskCount,
        mediumRiskCount,
        lowRiskCount
      }
    };
  }, [all_predictions, totalCustomers, highRiskCount, mediumRiskCount, lowRiskCount]);

  // Download functions (unchanged)
  const downloadAllCustomers = async () => {
    try {
      const downloadBtn = document.querySelector('.download-all-btn');
      const originalText = downloadBtn.innerHTML;
      downloadBtn.innerHTML = '<div class="spinner-small"></div> Generating Full Report...';
      downloadBtn.disabled = true;

      let fileToProcess = null;
      
      const fileInput = document.getElementById('batch-file');
      if (fileInput && fileInput.files && fileInput.files[0]) {
        fileToProcess = fileInput.files[0];
      } else if (window.uploadedBatchFile) {
        fileToProcess = window.uploadedBatchFile;
      } else {
        alert("❌ No CSV file found. Please go back to 'Batch Processing' and upload your CSV file again to download the complete report.");
        downloadBtn.innerHTML = originalText;
        downloadBtn.disabled = false;
        return;
      }

      const formData = new FormData();
      formData.append('file', fileToProcess);

      const response = await fetch('http://localhost:5000/api/batch/download-report', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        const errorText = await response.text();
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      a.download = 'churn_analysis_complete_report.csv';
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      downloadBtn.innerHTML = originalText;
      downloadBtn.disabled = false;

    } catch (error) {
      console.error('❌ Error downloading full report:', error);
      alert('Error downloading complete report. Please try again.');
      
      const downloadBtn = document.querySelector('.download-all-btn');
      if (downloadBtn) {
        downloadBtn.innerHTML = '<span class="btn-icon">📥</span> Download Complete Report';
        downloadBtn.disabled = false;
      }
    }
  };

  const downloadRiskCustomers = async (riskLevel) => {
    try {
      const downloadBtn = document.querySelector(`.download-${riskLevel}-btn`);
      const originalText = downloadBtn.innerHTML;
      downloadBtn.innerHTML = '<div class="spinner-small"></div> Generating Report...';
      downloadBtn.disabled = true;

      let fileToProcess = null;
      
      const fileInput = document.getElementById('batch-file');
      if (fileInput && fileInput.files && fileInput.files[0]) {
        fileToProcess = fileInput.files[0];
      } else if (window.uploadedBatchFile) {
        fileToProcess = window.uploadedBatchFile;
      } else {
        alert(`❌ No CSV file found. Please go back to 'Batch Processing' and upload your CSV file again to download ${riskLevel} risk customers.`);
        downloadBtn.innerHTML = originalText;
        downloadBtn.disabled = false;
        return;
      }

      const formData = new FormData();
      formData.append('file', fileToProcess);
      formData.append('risk_level', riskLevel);

      const response = await fetch('http://localhost:5000/api/batch/download-risk-customers', {
        method: 'POST',
        body: formData,
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      const blob = await response.blob();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.style.display = 'none';
      a.href = url;
      a.download = `churn_analysis_${riskLevel}_risk_customers.csv`;
      document.body.appendChild(a);
      a.click();
      window.URL.revokeObjectURL(url);
      document.body.removeChild(a);

      downloadBtn.innerHTML = originalText;
      downloadBtn.disabled = false;

    } catch (error) {
      console.error(`❌ Error downloading ${riskLevel} risk customers:`, error);
      alert(`Error downloading ${riskLevel} risk customers. Please try again.`);
      
      const downloadBtn = document.querySelector(`.download-${riskLevel}-btn`);
      if (downloadBtn) {
        const riskDisplay = riskLevel.charAt(0).toUpperCase() + riskLevel.slice(1);
        downloadBtn.innerHTML = `<span class="btn-icon">📥</span> Download ${riskDisplay} Risk`;
        downloadBtn.disabled = false;
      }
    }
  };

  // Business Analytics Visualizations
  const renderBusinessAnalytics = () => {
    if (!businessAnalyticsData) return null;

    const { payments, tenure, geography, marital, gender, revenue, overall } = businessAnalyticsData;

    return (
      <div className="business-analytics">
        {/* Revenue Impact Summary */}
        <div className="analytics-section">
          <h3>💰 Revenue Impact Summary</h3>
          <div className="revenue-summary">
            <div className="revenue-card critical">
              <div className="revenue-icon">🔥</div>
              <div className="revenue-content">
                <div className="revenue-label">High Risk Revenue</div>
                <div className="revenue-amount">₹{revenue.highRisk.toLocaleString('en-IN')}</div>
                <div className="revenue-subtext">{overall.highRiskCount} customers at risk</div>
              </div>
            </div>
            
            <div className="revenue-card warning">
              <div className="revenue-icon">⚠️</div>
              <div className="revenue-content">
                <div className="revenue-label">Medium Risk Revenue</div>
                <div className="revenue-amount">₹{revenue.mediumRisk.toLocaleString('en-IN')}</div>
                <div className="revenue-subtext">{overall.mediumRiskCount} customers</div>
              </div>
            </div>
            
            <div className="revenue-card total">
              <div className="revenue-icon">📊</div>
              <div className="revenue-content">
                <div className="revenue-label">Total Revenue at Risk</div>
                <div className="revenue-amount">₹{revenue.totalAtRisk.toLocaleString('en-IN')}</div>
                <div className="revenue-subtext">Across all risk levels</div>
              </div>
            </div>
          </div>
        </div>

        {/* Payment Method - Horizontal Bar Chart */}
        <div className="analytics-section">
          <h3>💳 Payment Method Distribution</h3>
          <div className="chart-container">
            <div className="horizontal-bars">
              {Object.entries(payments.methods).map(([method, count]) => {
                const percentage = (count / overall.totalCustomers) * 100;
                const risks = payments.risk[method] || { high: 0, medium: 0, low: 0 };
                const totalRisks = risks.high + risks.medium + risks.low;
                
                return (
                  <div key={method} className="bar-item">
                    <div className="bar-label">
                      <span className="method-name">{method}</span>
                      <span className="method-count">{count}</span>
                    </div>
                    <div className="bar-track">
                      <div 
                        className="bar-fill payment-fill"
                        style={{ width: `${percentage}%` }}
                        title={`${method}: ${count} customers (${percentage.toFixed(1)}%)`}
                      >
                        <div className="bar-risk-breakdown">
                          {risks.high > 0 && (
                            <div 
                              className="risk-segment high"
                              style={{ width: `${(risks.high / totalRisks) * 100}%` }}
                            ></div>
                          )}
                          {risks.medium > 0 && (
                            <div 
                              className="risk-segment medium"
                              style={{ width: `${(risks.medium / totalRisks) * 100}%` }}
                            ></div>
                          )}
                          {risks.low > 0 && (
                            <div 
                              className="risk-segment low"
                              style={{ width: `${(risks.low / totalRisks) * 100}%` }}
                            ></div>
                          )}
                        </div>
                      </div>
                    </div>
                    <div className="bar-percentage">{percentage.toFixed(1)}%</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Tenure Analysis - Histogram */}
        <div className="analytics-section">
          <h3>📅 Customer Tenure Distribution</h3>
          <div className="chart-container">
            <div className="histogram">
              {Object.entries(tenure).map(([bracket, data]) => {
                const maxCount = Math.max(...Object.values(tenure).map(t => t.count));
                const barHeight = (data.count / maxCount) * 200;
                
                return (
                  <div key={bracket} className="histogram-column">
                    <div className="column-value">{data.count}</div>
                    <div 
                      className="column-bar"
                      style={{ height: `${barHeight}px` }}
                      title={`${bracket}: ${data.count} customers`}
                    >
                      <div className="column-risk-overlay">
                        <div 
                          className="risk-overlay high"
                          style={{ height: `${(data.risk.high / data.count) * 100}%` }}
                        ></div>
                        <div 
                          className="risk-overlay medium"
                          style={{ height: `${(data.risk.medium / data.count) * 100}%` }}
                        ></div>
                      </div>
                    </div>
                    <div className="column-label">{bracket}</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* City Tier - Bar Graph */}
        <div className="analytics-section">
          <h3>🏙️ City Tier Performance</h3>
          <div className="chart-container">
            <div className="vertical-bars">
              {Object.entries(geography.cityTiers).map(([tier, count]) => {
                const maxCount = Math.max(...Object.values(geography.cityTiers));
                const barHeight = (count / maxCount) * 200;
                const revenue = geography.revenue[tier];
                const avgValue = revenue / count;
                
                return (
                  <div key={tier} className="vertical-bar-item">
                    <div className="vertical-bar-container">
                      <div 
                        className="vertical-bar"
                        style={{ height: `${barHeight}px` }}
                        title={`${tier}: ${count} customers, Revenue: ₹${revenue.toLocaleString('en-IN')}`}
                      >
                        <div className="bar-value">{count}</div>
                      </div>
                    </div>
                    <div className="vertical-bar-label">
                      <div>{tier}</div>
                      <div className="bar-subtext">₹{Math.round(avgValue).toLocaleString('en-IN')} avg</div>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Marital Status - Stacked Bar Chart */}
        <div className="analytics-section">
          <h3>💍 Marital Status Risk Distribution</h3>
          <div className="chart-container">
            <div className="stacked-bars">
              {Object.entries(marital.status).map(([status, count]) => {
                const risks = marital.risk[status];
                const total = risks.high + risks.medium + risks.low;
                
                return (
                  <div key={status} className="stacked-bar-item">
                    <div className="stacked-bar-label">
                      <span>{status}</span>
                      <span className="stacked-count">{count}</span>
                    </div>
                    <div className="stacked-bar-track">
                      <div 
                        className="stacked-segment high-risk"
                        style={{ width: `${(risks.high / total) * 100}%` }}
                        title={`High Risk: ${risks.high}`}
                      ></div>
                      <div 
                        className="stacked-segment medium-risk"
                        style={{ width: `${(risks.medium / total) * 100}%` }}
                        title={`Medium Risk: ${risks.medium}`}
                      ></div>
                      <div 
                        className="stacked-segment low-risk"
                        style={{ width: `${(risks.low / total) * 100}%` }}
                        title={`Low Risk: ${risks.low}`}
                      ></div>
                    </div>
                    <div className="stacked-bar-legend">
                      <span className="risk-legend high">{risks.high}H</span>
                      <span className="risk-legend medium">{risks.medium}M</span>
                      <span className="risk-legend low">{risks.low}L</span>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Gender - Pie Chart */}
        <div className="analytics-section">
          <h3>👥 Gender Distribution</h3>
          <div className="chart-container">
            <div className="pie-chart-container">
              <div className="pie-chart-gender">
                {Object.entries(gender).map(([gender, count], index, array) => {
                  const percentage = (count / overall.totalCustomers) * 100;
                  const previousPercentages = array.slice(0, index).reduce((acc, [, prevCount]) => 
                    acc + (prevCount / overall.totalCustomers) * 100, 0
                  );
                  
                  return (
                    <div
                      key={gender}
                      className="pie-segment-gender"
                      style={{
                        backgroundColor: `var(--gender-color-${index})`,
                        transform: `rotate(${previousPercentages * 3.6}deg)`,
                        clipPath: `conic-gradient(from 0deg at 50% 50%, var(--gender-color-${index}) 0% ${percentage}%, transparent ${percentage}% 100%)`
                      }}
                    ></div>
                  );
                })}
              </div>
              <div className="pie-legend-gender">
                {Object.entries(gender).map(([gender, count], index) => (
                  <div key={gender} className="legend-item-gender">
                    <div 
                      className="legend-color-gender"
                      style={{ backgroundColor: `var(--gender-color-${index})` }}
                    ></div>
                    <span className="legend-label-gender">{gender}</span>
                    <span className="legend-value-gender">
                      {count} ({(count / overall.totalCustomers * 100).toFixed(1)}%)
                    </span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  };

  // Render customer table (unchanged)
  const renderCustomerTable = () => {
    return (
      <div className="section-card all-predictions">
        <div className="predictions-header">
          <h3>👥 All Customer Predictions ({totalCustomers} Total)</h3>
          <div className="predictions-controls">
            <div className="search-box">
              <input
                type="text"
                placeholder="Search customers..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
                className="search-input"
              />
            </div>
            <div className="pagination-controls">
              <select 
                value={itemsPerPage} 
                onChange={handleItemsPerPageChange}
                className="items-per-page-select"
              >
                <option value={20}>20 per page</option>
                <option value={50}>50 per page</option>
                <option value={100}>100 per page</option>
                <option value={200}>200 per page</option>
              </select>
              
              <div className="pagination-info">
                Showing {startIndex + 1}-{Math.min(endIndex, filteredPredictions.length)} of {filteredPredictions.length} customers
              </div>
              
              <div className="pagination-buttons">
                <button
                  onClick={() => handlePageChange(currentPage - 1)}
                  disabled={currentPage === 1}
                  className="pagination-btn"
                >
                  Previous
                </button>
                <span className="page-info">
                  Page {currentPage} of {totalPages}
                </span>
                <button
                  onClick={() => handlePageChange(currentPage + 1)}
                  disabled={currentPage === totalPages}
                  className="pagination-btn"
                >
                  Next
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="predictions-table-container">
          <div className="predictions-table">
            <table>
              <thead>
                <tr>
                  <th>Customer ID</th>
                  <th>Churn Probability</th>
                  <th>Risk Level</th>
                  <th>Prediction</th>
                  <th>Tenure (Months)</th>
                  <th>Order Count</th>
                  <th>Cashback</th>
                  <th>Payment Type</th>
                  <th>City Tier</th>
                  <th>Gender</th>
                  <th>Marital Status</th>
                  <th>Satisfaction</th>
                  <th>Customer Value</th>
                </tr>
              </thead>
              <tbody>
                {currentPredictions.map((customer, index) => {
                  const riskLevel = customer.Risk_Level || 'Unknown';
                  const churnProbability = customer.Churn_Probability || 0;
                  const customerValue = ((customer.OrderCount || 0) * 850) + (customer.CashbackAmount || 0);
                  
                  return (
                    <tr key={index}>
                      <td className="customer-id">
                        {customer.Customer_ID || customer.CustomerID || `CUST_${startIndex + index + 1}`}
                      </td>
                      <td>
                        <div className="probability-bar">
                          <div 
                            className="probability-fill"
                            style={{ width: `${churnProbability * 100}%` }}
                          ></div>
                          <span className="probability-text">
                            {(churnProbability * 100).toFixed(1)}%
                          </span>
                        </div>
                      </td>
                      <td>
                        <span className={`risk-badge ${riskLevel.toLowerCase().replace(' ', '-')}`}>
                          {riskLevel}
                        </span>
                      </td>
                      <td>
                        <span className={`prediction ${customer.Predicted_Churn ? 'churn' : 'no-churn'}`}>
                          {customer.Predicted_Churn ? "🚨 Churn" : "✅ Retain"}
                        </span>
                      </td>
                      <td>{customer.Tenure || 'N/A'}</td>
                      <td>{customer.OrderCount || 'N/A'}</td>
                      <td>₹{(customer.CashbackAmount || 0).toLocaleString('en-IN')}</td>
                      <td>{customer.PreferredPaymentMode || customer.preferred_payment_mode || 'N/A'}</td>
                      <td>{customer.CityTier || customer.city_tier || 'N/A'}</td>
                      <td>{customer.Gender || customer.gender || 'N/A'}</td>
                      <td>{customer.MaritalStatus || customer.marital_status || 'N/A'}</td>
                      <td>
                        <div className="satisfaction-score">
                          {customer.SatisfactionScore || 'N/A'}
                          {customer.SatisfactionScore && (
                            <span className="score-stars">
                              {'★'.repeat(customer.SatisfactionScore)}{'☆'.repeat(5 - customer.SatisfactionScore)}
                            </span>
                          )}
                        </div>
                      </td>
                      <td>₹{customerValue.toLocaleString('en-IN')}</td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
        </div>

        {filteredPredictions.length === 0 && (
          <div className="no-results">
            <p>No customers found matching your search criteria.</p>
          </div>
        )}
      </div>
    );
  };

  // Render overview (unchanged)
  const renderOverview = () => {
    return (
      <>
        {/* Dataset Overview */}
        <div className="section-card dataset-overview">
          <h3>📁 Dataset Overview</h3>
          <div className="dataset-stats-grid">
            <div className="stat-card">
              <div className="stat-value">{dataset_info.total_customers}</div>
              <div className="stat-label">Total Customers</div>
            </div>
            <div className="stat-card">
              <div className="stat-value">{dataset_info.total_features}</div>
              <div className="stat-label">Features Analyzed</div>
            </div>
            <div className="stat-card">
              <div className="stat-value">{dataset_info.dataset_size_kb.toFixed(1)} KB</div>
              <div className="stat-label">Dataset Size</div>
            </div>
            <div className="stat-card">
              <div className="stat-value">{risk_analysis.total_predicted_churn}</div>
              <div className="stat-label">Predicted Churn</div>
            </div>
          </div>
          
          <div className="data-source-info">
            <span className="source-label">Data Source:</span>
            <span className="source-value">{data_source === "demo" ? "Demo Data" : "Uploaded CSV"}</span>
          </div>
        </div>

        {/* Risk Analysis */}
        <div className="section-card risk-analysis">
          <h3>⚠️ Risk Analysis Summary</h3>
          <div className="risk-metrics-grid">
            <div className="risk-metric">
              <div className="metric-value">{risk_analysis.average_probability?.toFixed(3) || '0.000'}</div>
              <div className="metric-label">Average Churn Probability</div>
            </div>
            <div className="risk-metric">
              <div className="metric-value">{((risk_analysis.churn_rate || 0) * 100).toFixed(1)}%</div>
              <div className="metric-label">Overall Churn Rate</div>
            </div>
            <div className="risk-metric">
              <div className="metric-value">{customer_segmentation.high_risk_customers || 0}</div>
              <div className="metric-label">High-Risk Customers</div>
            </div>
            <div className="risk-metric">
              <div className="metric-value">₹{(customer_segmentation.potential_revenue_loss || 0).toLocaleString('en-IN')}</div>
              <div className="metric-label">Potential Revenue Loss</div>
            </div>
          </div>

          {/* Risk Distribution */}
          <div className="risk-distribution">
            <h4>Risk Level Distribution</h4>
            <div className="distribution-bars">
              {Object.entries(riskDistribution).map(([riskLevel, count]) => {
                const percentage = totalCustomers > 0 ? (count / totalCustomers * 100).toFixed(1) : 0;
                let barColor = "";
                
                if (riskLevel.includes("High")) barColor = "high-risk";
                else if (riskLevel.includes("Moderate")) barColor = "medium-risk";
                else barColor = "low-risk";

                return (
                  <div key={riskLevel} className="distribution-item">
                    <div className="risk-label">{riskLevel}</div>
                    <div className="bar-container">
                      <div 
                        className={`risk-bar ${barColor}`}
                        style={{ width: `${percentage}%` }}
                      >
                        <span className="bar-count">{count} customers</span>
                      </div>
                    </div>
                    <div className="risk-percentage">{percentage}%</div>
                  </div>
                );
              })}
            </div>
          </div>
        </div>

        {/* Feature Analysis */}
        {feature_analysis && Object.keys(feature_analysis).length > 0 && (
          <div className="section-card feature-analysis">
            <h3>🔍 High-Risk Customer Profile</h3>
            <div className="feature-grid">
              {Object.entries(feature_analysis).slice(0, 6).map(([feature, stats]) => (
                <div key={feature} className="feature-card">
                  <div className="feature-name">{feature}</div>
                  <div className="feature-stats">
                    <div className="stat">
                      <span className="stat-label">Avg:</span>
                      <span className="stat-value">{(stats.mean || 0).toFixed(2)}</span>
                    </div>
                    <div className="stat">
                      <span className="stat-label">Med:</span>
                      <span className="stat-value">{(stats.median || 0).toFixed(2)}</span>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}
      </>
    );
  };

  return (
    <div className="batch-dashboard">
      <div className="dashboard-header">
        <h2>📊 Customer Analytics Dashboard</h2>
        <div className="header-actions">
          {/* Navigation Tabs */}
          <div className="dashboard-tabs">
            <button 
              className={`tab-button ${activeTab === 'overview' ? 'active' : ''}`}
              onClick={() => setActiveTab('overview')}
            >
              📋 Executive Summary
            </button>
            <button 
              className={`tab-button ${activeTab === 'visualization' ? 'active' : ''}`}
              onClick={() => setActiveTab('visualization')}
            >
              📈 Business Analytics
            </button>
            <button 
              className={`tab-button ${activeTab === 'customers' ? 'active' : ''}`}
              onClick={() => setActiveTab('customers')}
            >
              👥 Customer Details
            </button>
          </div>
        </div>
      </div>

      {/* Tab Content */}
      <div className="tab-content">
        {activeTab === 'overview' && renderOverview()}
        {activeTab === 'visualization' && renderBusinessAnalytics()}
        {activeTab === 'customers' && renderCustomerTable()}
      </div>

      {/* Report Download Section */}
      <div className="section-card download-section">
        <h3>📩 Download Reports</h3>
        
        <div className="download-main-section">
          <div className="download-option-full">
            <h4>📊 Complete Analysis Report</h4>
            <p>Download the <strong>complete dataset</strong> with predictions for <strong>ALL {totalCustomers} customers</strong>, including churn probabilities, risk levels, and personalized retention recommendations in CSV format.</p>
            <button className="download-btn primary download-all-btn" onClick={downloadAllCustomers}>
              <span className="btn-icon">📩</span>
              Download Complete Report (All {totalCustomers} Customers)
            </button>
          </div>
        </div>

        <div className="risk-categories-section">
          <h4>📉 Download by Risk Level</h4>
          <p>Download specific customer segments based on their churn risk level:</p>
          
          <div className="risk-cards-horizontal">
            <div className="risk-card-horizontal high-risk">
              <div className="risk-card-header">
                <span className="risk-icon">🚨</span>
                <div className="risk-title-container">
                  <h5>High Risk Customers</h5>
                  <div className="customer-count-badge">
                    {highRiskCount} customers
                  </div>
                </div>
              </div>
              <button 
                className="download-btn compact high-risk-btn download-high-btn"
                onClick={() => downloadRiskCustomers('high')}
                disabled={highRiskCount === 0}
              >
                <span className="btn-icon">📩</span>
                Download High Risk
              </button>
            </div>

            <div className="risk-card-horizontal medium-risk">
              <div className="risk-card-header">
                <span className="risk-icon">⚠️</span>
                <div className="risk-title-container">
                  <h5>Medium Risk Customers</h5>
                  <div className="customer-count-badge">
                    {mediumRiskCount} customers
                  </div>
                </div>
              </div>
              <button 
                className="download-btn compact medium-risk-btn download-medium-btn"
                onClick={() => downloadRiskCustomers('medium')}
                disabled={mediumRiskCount === 0}
              >
                <span className="btn-icon">📩</span>
                Download Medium Risk
              </button>
            </div>

            <div className="risk-card-horizontal low-risk">
              <div className="risk-card-header">
                <span className="risk-icon">✅</span>
                <div className="risk-title-container">
                  <h5>Low Risk Customers</h5>
                  <div className="customer-count-badge">
                    {lowRiskCount} customers
                  </div>
                </div>
              </div>
              <button 
                className="download-btn compact low-risk-btn download-low-btn"
                onClick={() => downloadRiskCustomers('low')}
                disabled={lowRiskCount === 0}
              >
                <span className="btn-icon">📩</span>
                Download Low Risk
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Hidden file input for re-upload */}
      <input
        type="file"
        accept=".csv"
        id="batch-file"
        style={{ display: 'none' }}
        onChange={() => {}}
      />
    </div>
  );
}

export default BatchDashboard;
